CREATE DATABASE IF NOT EXISTS menu_randomizer CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;

USE menu_randomizer;

CREATE TABLE IF NOT EXISTS `menu` (
  `id` int NOT NULL AUTO_INCREMENT,
  `name` varchar(255) NOT NULL,
  `category` varchar(50) NOT NULL COMMENT 'adult or baby',
  `description` text,
  `image` varchar(255),
  `ingredients` text,
  `steps` text,
  `nutrition` text,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_category` (`category`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

